// Filter: Should Respond (DM)
// DMs: always respond unless from a bot or empty.

const raw = $input.item.json;

// Ignore messages from bots
if (raw.author && raw.author.bot) {
  return [];
}
// Also check authorId-based bot detection (katerlol flat fields)
if (raw.authorBot === true) {
  return [];
}

// Ignore empty messages
if (!raw.content && (!raw.attachments || raw.attachments.length === 0)) {
  return [];
}

// DMs: always respond
return [{ json: { ...raw, _shouldRespond: true, _isDM: true } }];

// Normalize DM Message — Discord DM to internal schema
// DMs: no guildId, channel_id IS the DM channel, is_dm always true

const raw = $input.item.json;

// katerlol emits flat fields for DMs just like guild messages
const userId = raw.authorId || (raw.author && raw.author.id) || 'unknown';
const username = raw.authorName || (raw.author && (raw.author.globalName || raw.author.username)) || 'unknown';
const channelId = raw.channelId || raw.channel_id || '';

const normalized = {
  source_channel: 'discord',
  channel_id: channelId,
  guild_id: null,
  user_id: userId,
  username: username,
  message_text: (raw.content || '').trim(),
  message_id: raw.id || raw.message_id || '',
  is_dm: true,
  is_mention: false,
  is_edit: !!raw.editedTimestamp,
  conversation_privacy: 'private',
  attachments: (raw.attachments || []).map(function(a) {
    return {
      type: a.contentType || 'unknown',
      size: a.size || 0,
      url: a.url || null,
      filename: a.name || a.filename || 'unknown'
    };
  }),
  timestamp: raw.createdTimestamp || Date.now(),
  location_label: 'Discord — Private DM',
  // Phase 4: bare user_id session key — dm_ prefix removed for room-to-room continuity.
  // Will be overridden to bare person_id after identity resolution in Merge person_id (DM).
  // Privacy isolation is via conversation_privacy: 'private' flag, NOT session key separation.
  session_key: userId
};

return [{ json: normalized }];

// Merge person_id + set session key
// Phase 4: session_key = person_id (bare UUID) for ALL contexts.
// The dm_ prefix is removed — Aerys follows a person across Discord DMs, guild, and Telegram
// using one unified conversation buffer per person.
// Privacy isolation is via conversation_privacy: 'private' flag and privacy_level filtering
// on long-term memories (Phase 4 Plan 2), NOT by session key separation.

const resolverOutput = $input.item.json;
const originalMsg = $('Restore Context (DM)').item.json;
const personId = resolverOutput.person_id;

return [{
  json: {
    ...originalMsg,
    person_id: personId,
    display_name: resolverOutput.display_name,
    // Bare person_id — enables room-to-room conversation continuity
    session_key: personId,
    // Ensure privacy flag is set
    conversation_privacy: 'private'
  }
}];

const input = $input.first().json;
return [{
  json: {
    person_id: input.person_id,
    channel_id: input.channel_id || input.session_key,
    message_text: input.message_content || input.message_text || input.content || '',
    privacy_context: 'private'
  }
}];

const memResult = $input.first().json;
const original = $('Build Thread Context (DM)').item.json;
return [{
  json: {
    ...original,
    memory_context: memResult.memory_context || ''
  }
}];

const profileResp = $input.first().json;
const original = $('Merge Memory Result (DM)').item.json;
const profileData = profileResp.profile || {};
const lines = profileData.lines || [];
const coldStart = profileData.cold_start !== undefined ? profileData.cold_start : true;

const profileContext = lines.length > 0 ? lines.join('\n') : '';

return [{
  json: {
    ...original,
    profile_context: profileContext,
    cold_start: coldStart
  }
}];

// Build timestamped thread context from n8n_chat_histories
// Receives N items (one per DB row); outputs 1 item with thread_context injected

const rows = $input.all();
const upstream = $('Merge person_id (DM)').item.json;

// Filter out sentinel, nulls, and any error rows
const validRows = rows.filter(r =>
  r.json.role !== 'sentinel' &&
  r.json.content !== null &&
  r.json.content !== undefined &&
  !r.json.error
);

let thread_context = null;

if (validRows.length > 0) {
  // Sort chronologically (query returned DESC)
  const sorted = validRows.sort((a, b) =>
    new Date(a.json.created_at) - new Date(b.json.created_at)
  );

  const displayName = upstream.display_name || upstream.username || 'User';

  const lines = sorted.map(r => {
    const ts = new Date(r.json.created_at);
    const formatted = ts.toLocaleString('en-US', {
      timeZone: 'America/New_York',
      month: 'short', day: 'numeric',
      hour: 'numeric', minute: '2-digit',
      hour12: true, timeZoneName: 'short'
    });
    const speaker = r.json.role === 'human' ? displayName : 'Aerys';
    const content = (r.json.content || '').trim();
    const snippet = content.length > 300 ? content.substring(0, 300) + '...' : content;
    return `[${formatted}] ${speaker}: ${snippet}`;
  });

  thread_context = lines.join('\n');
}

return [{
  json: {
    ...upstream,
    thread_context
  }
}];

